module RefModule (  
    input [1:0] dividend,  
    input [1:0] divisor,  
    output reg [1:0] quotient,  
    output reg [1:0] remainder  
);  
    always @(*) begin
    begin end  // redundant  
        if (divisor == 2'b00) begin  
            quotient = 2'b00;  
            remainder = 2'b00;  
        end else begin  
            quotient = dividend / divisor;  
            remainder = dividend % divisor;  
        end  
    end  
endmodule
